// index.js
const sgMail = require("@sendgrid/mail");
const twilio = require("twilio");

// Read secrets from environment variables — NEVER hardcode them
function getRequiredEnv(name) {
  const value = process.env[name];
  if (!value) {
    throw new Error(
      `Missing required environment variable: ${name}. ` +
      `Set it in local.settings.json for local dev or in Application Settings (with Key Vault references) for production.`
    );
  }
  return value;
}

// Input validation helpers
function isValidEmail(email) {
  // Basic RFC 5322 compliant check
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return typeof email === "string" && emailRegex.test(email) && email.length <= 254;
}

function isValidPhone(phone) {
  // E.164 format
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return typeof phone === "string" && phoneRegex.test(phone);
}

function sanitizeString(input, maxLength = 1000) {
  if (typeof input !== "string") return "";
  return input.trim().slice(0, maxLength);
}

module.exports = async function (context, req) {
  // Only accept POST
  if (req.method !== "POST") {
    context.res = { status: 405, body: { error: "Method not allowed" } };
    return;
  }

  // Validate Content-Type
  const contentType = (req.headers["content-type"] || "").toLowerCase();
  if (!contentType.includes("application/json")) {
    context.res = {
      status: 415,
      body: { error: "Content-Type must be application/json" },
    };
    return;
  }

  try {
    const body = req.body;

    if (!body || !body.type) {
      context.res = {
        status: 400,
        body: { error: "Request body must include 'type' ('email', 'sms', or 'both')" },
      };
      return;
    }

    const notificationType = sanitizeString(body.type).toLowerCase();
    const results = {};

    if (notificationType === "email" || notificationType === "both") {
      // Validate email inputs
      const toEmail = sanitizeString(body.toEmail, 254);
      const fromEmail = sanitizeString(body.fromEmail || process.env.DEFAULT_FROM_EMAIL || "", 254);
      const subject = sanitizeString(body.subject, 500);
      const emailBody = sanitizeString(body.emailBody, 10000);

      if (!isValidEmail(toEmail)) {
        context.res = {
          status: 400,
          body: { error: "Invalid or missing 'toEmail' address" },
        };
        return;
      }

      if (!isValidEmail(fromEmail)) {
        context.res = {
          status: 400,
          body: { error: "Invalid or missing 'fromEmail' address. Set DEFAULT_FROM_EMAIL in environment or provide 'fromEmail' in request." },
        };
        return;
      }

      if (!subject) {
        context.res = {
          status: 400,
          body: { error: "Missing 'subject' for email" },
        };
        return;
      }

      if (!emailBody) {
        context.res = {
          status: 400,
          body: { error: "Missing 'emailBody' for email" },
        };
        return;
      }

      const sendgridApiKey = getRequiredEnv("SENDGRID_API_KEY");
      sgMail.setApiKey(sendgridApiKey);

      const msg = {
        to: toEmail,
        from: fromEmail,
        subject: subject,
        // Send as plain text to avoid XSS in email clients; use 'html' only if you sanitize rigorously
        text: emailBody,
      };

      const [response] = await sgMail.send(msg);
      results.email = {
        success: true,
        statusCode: response.statusCode,
        message: `Email sent to ${toEmail}`,
      };

      context.log.info(`Email sent successfully to ${toEmail}`);
    }

    if (notificationType === "sms" || notificationType === "both") {
      // Validate SMS inputs
      const toPhone = sanitizeString(body.toPhone, 20);
      const fromPhone = sanitizeString(body.fromPhone || process.env.TWILIO_FROM_PHONE || "", 20);
      const smsBody = sanitizeString(body.smsBody, 1600); // SMS max ~1600 chars

      if (!isValidPhone(toPhone)) {
        context.res = {
          status: 400,
          body: { error: "Invalid or missing 'toPhone'. Use E.164 format (e.g., +14155551234)" },
        };
        return;
      }

      if (!isValidPhone(fromPhone)) {
        context.res = {
          status: 400,
          body: { error: "Invalid or missing 'fromPhone'. Set TWILIO_FROM_PHONE in environment or provide 'fromPhone' in request." },
        };
        return;
      }

      if (!smsBody) {
        context.res = {
          status: 400,
          body: { error: "Missing 'smsBody' for SMS" },
        };
        return;
      }

      const twilioSid = getRequiredEnv("TWILIO_ACCOUNT_SID");
      const twilioAuthToken = getRequiredEnv("TWILIO_AUTH_TOKEN");

      const twilioClient = twilio(twilioSid, twilioAuthToken);

      const message = await twilioClient.messages.create({
        body: smsBody,
        from: fromPhone,
        to: toPhone,
      });

      results.sms = {
        success: true,
        messageSid: message.sid,
        message: `SMS sent to ${toPhone}`,
      };

      context.log.info(`SMS sent successfully to ${toPhone}, SID: ${message.sid}`);
    }

    if (!results.email && !results.sms) {
      context.res = {
        status: 400,
        body: { error: "Invalid 'type'. Must be 'email', 'sms', or 'both'" },
      };
      return;
    }

    context.res = {
      status: 200,
      headers: { "Content-Type": "application/json" },
      body: { success: true, results },
    };
  } catch (error) {
    // Log full error internally, return safe message to client
    context.log.error("Notification function error:", error.message);

    // Don't leak internal details
    const statusCode = error.message.includes("Missing required environment variable") ? 500 : 502;
    context.res = {
      status: statusCode,
      headers: { "Content-Type": "application/json" },
      body: {
        success: false,
        error: statusCode === 500
          ? "Server configuration error. Check function logs."
          : "Failed to send notification. Check function logs for details.",
      },
    };
  }
};